const webhookInput = $input.first().json;

// Payload thật từ Jenkins nằm trong body
const input = webhookInput.body || webhookInput;

const build = input.build || {};
const scm = input.scm || input.git || {};

const jobName =
  input.job ||
  input.name ||
  input.job_name ||
  input.jobName ||
  input.project_name ||
  build.jobName ||
  'Jenkins Job';

const buildNumber =
  input.buildNumber ||
  input.build_number ||
  build.number ||
  input.number ||
  'N/A';

const rawStatus =
  input.status ||
  input.build_status ||
  input.buildStatus ||
  input.result ||
  build.status ||
  'UNKNOWN';

const status = String(rawStatus).toUpperCase();

const buildUrl =
  input.url ||
  input.build_url ||
  input.buildUrl ||
  build.full_url ||
  build.url ||
  '';

const branch =
  input.branch ||
  scm.branch ||
  input.git_branch ||
  input.ref ||
  '';

const commit =
  input.commit ||
  scm.commit ||
  input.git_commit ||
  '';

const author =
  input.author ||
  scm.author ||
  input.git_author ||
  '';

const duration =
  input.duration ||
  input.duration_ms ||
  build.duration ||
  '';

function detectProjectKey(payload, name) {
  const explicit = payload.project_key || payload.projectKey || payload.project || '';
  const s = String(explicit || name || '').toLowerCase();

  if (s.includes('redeemgiftapi') || s.includes('redeem_gift_api') || s.includes('gift_api') || s.includes('_api') || s.endsWith('api') || s.includes(' api')) {
    return 'RedeemGiftAPI';
  }

  if (s.includes('redeemgiftclient') || s.includes('redeem_gift_client') || s.includes('gift_client') || s.includes('client') || s.includes('frontend') || s.includes('fe')) {
    return 'RedeemGiftClient';
  }

  return '';
}

function toDbStatus(s) {
  if (['SUCCESS', 'SUCCEEDED', 'OK', 'PASSED'].includes(s)) return 'success';
  if (['FAILURE', 'FAILED', 'ERROR'].includes(s)) return 'failed';
  if (['UNSTABLE', 'WARNING'].includes(s)) return 'unstable';
  if (['ABORTED', 'CANCELLED', 'CANCELED'].includes(s)) return 'aborted';
  if (['STARTED', 'RUNNING', 'IN_PROGRESS'].includes(s)) return 'running';
  return 'unknown';
}

const project_key = detectProjectKey(input, jobName);
const status_db = toDbStatus(status);

let emoji = 'ℹ️';

if (['SUCCESS', 'SUCCEEDED', 'OK', 'PASSED'].includes(status)) {
  emoji = '✅';
}

if (['FAILURE', 'FAILED', 'ERROR'].includes(status)) {
  emoji = '❌';
}

if (['UNSTABLE', 'WARNING'].includes(status)) {
  emoji = '⚠️';
}

if (['ABORTED', 'CANCELLED', 'CANCELED'].includes(status)) {
  emoji = '⛔';
}

if (['STARTED', 'RUNNING', 'IN_PROGRESS'].includes(status)) {
  emoji = '🚀';
}

const lines = [
  `${emoji} <strong> Jenkins Build ${status} </strong>`,
  `Project: ${project_key || 'Không xác định'}`,
  `Job: ${jobName}`,
  `Build: #${buildNumber}`,
];

if (branch) lines.push(`Branch: ${branch}`);
if (commit) lines.push(`Commit: ${String(commit).slice(0, 12)}`);
if (author) lines.push(`Author: ${author}`);
if (duration) lines.push(`Duration: ${duration}`);
if (buildUrl) lines.push(`URL: ${buildUrl}`);

return [
  {
    json: {
      project_key,
      jobName,
      buildNumber,
      status,
      status_db,
      buildUrl,
      branch,
      commit,
      author,
      duration,
      telegramMessage: lines.join('\n'),
      originalPayload: input,
      rawWebhookPayload: webhookInput,
    },
  },
];

const item = $input.first().json;

const statusCode = item.statusCode || item.status || 'unknown';

let projectKey = '';
let jobType = '';
try {
  const lock = $('Create build lock').first().json || {};
  projectKey = lock.project_key || '';
  jobType = lock.job_type || '';
} catch (e) {}

return [
  {
    json: {
      chat_id: (() => {
        try {
          const msg = $('Telegram Trigger').first().json.message || $('Telegram Trigger').first().json.edited_message || {};
          return String(msg.chat?.id || '');
        } catch (e) {
          return '';
        }
      })(),
      project_key: projectKey,
      job_type: jobType,
      telegramMessage:
        `🚀 Đã nhận lệnh build ${projectKey || 'Jenkins'}\n\n` +
        `HTTP Status: ${statusCode}\n` +
        `Trạng thái: Jenkins đã nhận request và đưa job vào queue.\n\n` +
        `Kết quả sẽ được trả về khi Jenkins build xong.`
    }
  }
];

const root = $('Telegram Trigger').first().json || {};
const msg = root.message || root.edited_message || {};
const text = String(msg.text || '').trim();
const lower = text.toLowerCase();

const chatId = msg.chat?.id ? String(msg.chat.id) : '';
const user = msg.from || {};
const requestedBy = user.username
  ? '@' + user.username
  : [user.first_name, user.last_name].filter(Boolean).join(' ') || String(user.id || '');

let project_key = '';
let job_type = '';
let job_name = '';

if (/^api$/.test(lower)) {
  project_key = 'RedeemGiftAPI';
  job_type = 'api';
  job_name = 'pl_redeem_gift_api';
}

if (/^client$/.test(lower)) {
  project_key = 'RedeemGiftClient';
  job_type = 'client';
  job_name = 'pl_redeem_gift_client';
}

return [{
  json: {
    chat_id: chatId,
    text,
    project_key,
    job_type,
    job_name,
    requested_by: requestedBy,
    is_valid_build_command: Boolean(project_key)
  }
}];

