{{ (() => {
  const q = (v) => "'" + String(v ?? '').replace(/'/g, "''") + "'";
  const projectKey = $json.project_key || '';
  const chatId = $json.chat_id || '';
  const requestedBy = $json.requested_by || '';
  const jobType = $json.job_type || '';
  const jobName = $json.job_name || '';

  return `CREATE TABLE IF NOT EXISTS jenkins_build_locks (
  project_key TEXT PRIMARY KEY,
  chat_id TEXT,
  requested_by TEXT,
  status TEXT NOT NULL,
  build_number TEXT,
  started_at TIMESTAMP DEFAULT NOW(),
  finished_at TIMESTAMP,
  updated_at TIMESTAMP DEFAULT NOW()
);

ALTER TABLE jenkins_build_locks ADD COLUMN IF NOT EXISTS chat_id TEXT;
ALTER TABLE jenkins_build_locks ADD COLUMN IF NOT EXISTS requested_by TEXT;
ALTER TABLE jenkins_build_locks ADD COLUMN IF NOT EXISTS status TEXT NOT NULL DEFAULT 'running';
ALTER TABLE jenkins_build_locks ADD COLUMN IF NOT EXISTS build_number TEXT;
ALTER TABLE jenkins_build_locks ADD COLUMN IF NOT EXISTS started_at TIMESTAMP DEFAULT NOW();
ALTER TABLE jenkins_build_locks ADD COLUMN IF NOT EXISTS finished_at TIMESTAMP;
ALTER TABLE jenkins_build_locks ADD COLUMN IF NOT EXISTS updated_at TIMESTAMP DEFAULT NOW();

WITH existing AS (
  SELECT *
  FROM jenkins_build_locks
  WHERE project_key = ${q(projectKey)}
    AND status = 'running'
    AND started_at > NOW() - INTERVAL '2 hours'
  LIMIT 1
)
SELECT
  ${q(projectKey)} AS project_key,
  ${q(chatId)} AS chat_id,
  ${q(requestedBy)} AS requested_by,
  ${q(jobType)} AS job_type,
  ${q(jobName)} AS job_name,
  EXISTS(SELECT 1 FROM existing) AS is_running,
  COALESCE((SELECT status FROM existing), '') AS current_status,
  COALESCE((SELECT started_at::text FROM existing), '') AS started_at,
  COALESCE((SELECT requested_by FROM existing), '') AS current_requested_by,
  COALESCE((SELECT build_number FROM existing), '') AS build_number;`;
})() }}

