{{ (() => {
  const q = (v) => "'" + String(v ?? '').replace(/'/g, "''") + "'";
  const projectKey = $json.project_key || '';
  const statusDb = $json.status_db || 'unknown';
  const buildNumber = $json.buildNumber || '';
  const telegramMessage = $json.telegramMessage || '';
  const jobName = $json.jobName || '';
  const status = $json.status || '';

  return `CREATE TABLE IF NOT EXISTS jenkins_build_locks (
  project_key TEXT PRIMARY KEY,
  chat_id TEXT,
  requested_by TEXT,
  status TEXT NOT NULL,
  build_number TEXT,
  started_at TIMESTAMP DEFAULT NOW(),
  finished_at TIMESTAMP,
  updated_at TIMESTAMP DEFAULT NOW()
);

UPDATE jenkins_build_locks
SET status = ${q(statusDb)},
    build_number = ${q(buildNumber)},
    finished_at = CASE WHEN ${q(statusDb)} = 'running' THEN finished_at ELSE NOW() END,
    updated_at = NOW()
WHERE project_key = ${q(projectKey)};

SELECT
  ${q(projectKey)} AS project_key,
  ${q(jobName)} AS jobName,
  ${q(buildNumber)} AS buildNumber,
  ${q(status)} AS status,
  ${q(statusDb)} AS status_db,
  ${q(telegramMessage)} AS telegramMessage;`;
})() }}

