  const q = (v) => "'" + String(v ?? '').replace(/'/g, "''") + "'";
  const projectKey = $json.project_key || '';
  const chatId = $json.chat_id || '';
  const requestedBy = $json.requested_by || '';
  const jobType = $json.job_type || '';
  const jobName = $json.job_name || '';

  return `CREATE TABLE IF NOT EXISTS jenkins_build_locks (
  project_key TEXT PRIMARY KEY,
  chat_id TEXT,
  requested_by TEXT,
  status TEXT NOT NULL,
  build_number TEXT,
  started_at TIMESTAMP DEFAULT NOW(),
  finished_at TIMESTAMP,
  updated_at TIMESTAMP DEFAULT NOW()
);

ALTER TABLE jenkins_build_locks ADD COLUMN IF NOT EXISTS chat_id TEXT;
ALTER TABLE jenkins_build_locks ADD COLUMN IF NOT EXISTS requested_by TEXT;
ALTER TABLE jenkins_build_locks ADD COLUMN IF NOT EXISTS status TEXT NOT NULL DEFAULT 'running';
ALTER TABLE jenkins_build_locks ADD COLUMN IF NOT EXISTS build_number TEXT;
ALTER TABLE jenkins_build_locks ADD COLUMN IF NOT EXISTS started_at TIMESTAMP DEFAULT NOW();
ALTER TABLE jenkins_build_locks ADD COLUMN IF NOT EXISTS finished_at TIMESTAMP;
ALTER TABLE jenkins_build_locks ADD COLUMN IF NOT EXISTS updated_at TIMESTAMP DEFAULT NOW();

WITH upserted AS (
  INSERT INTO jenkins_build_locks (
    project_key,
    chat_id,
    requested_by,
    status,
    build_number,
    started_at,
    finished_at,
    updated_at
  )
  VALUES (
    ${q(projectKey)},
    ${q(chatId)},
    ${q(requestedBy)},
    'running',
    NULL,
    NOW(),
    NULL,
    NOW()
  )
  ON CONFLICT (project_key)
  DO UPDATE SET
    chat_id = EXCLUDED.chat_id,
    requested_by = EXCLUDED.requested_by,
    status = 'running',
    build_number = NULL,
    started_at = NOW(),
    finished_at = NULL,
    updated_at = NOW()
  WHERE jenkins_build_locks.status <> 'running'
     OR jenkins_build_locks.started_at < NOW() - INTERVAL '2 hours'
  RETURNING
    project_key,
    chat_id,
    requested_by,
    status,
    started_at,
    build_number
),
current_lock AS (
  SELECT *
  FROM jenkins_build_locks
  WHERE project_key = ${q(projectKey)}
  LIMIT 1
)
SELECT
  ${q(projectKey)} AS project_key,
  COALESCE((SELECT chat_id FROM upserted), (SELECT chat_id FROM current_lock), ${q(chatId)}) AS chat_id,
  ${q(requestedBy)} AS requested_by,
  ${q(jobType)} AS job_type,
  ${q(jobName)} AS job_name,
  EXISTS(SELECT 1 FROM upserted) AS lock_acquired,
  NOT EXISTS(SELECT 1 FROM upserted) AS is_running,
  COALESCE((SELECT status FROM upserted), (SELECT status FROM current_lock), '') AS current_status,
  COALESCE((SELECT started_at::text FROM upserted), (SELECT started_at::text FROM current_lock), '') AS started_at,
  COALESCE((SELECT requested_by FROM current_lock), ${q(requestedBy)}) AS current_requested_by,
  COALESCE((SELECT build_number FROM current_lock), '') AS build_number;`;
})() }}
